[-] 没有直接搜到明文 Flag。&quot;) print(&quot;[*] 出题人可能把 Flag 动态加密了。请在 Linux 虚拟机中运行 ./fixed_payload.elf，或者把它扔进 IDA Pro 里逆向！&quot;) except Exception as e: print(f&quot;[-] 搜索出错: &#123;e&#125;&quot;)if __name__ == &#x27;__main__&#x27;:提取出的 payload 并不是压缩包，而是一个完整的 Linux ELF 可执行文件 继续ida分析这个fixed_payload.elf，main函数非常短，在栈上分配了 336 字节的数组 v4。使用qmemcpy将 .data 段 off_4020 处的 336 字节拷贝到 v4。程序并未对 v4 进行任何处理，只是打印了提示：每个 MD5 哈希对应一个 ASCII 字符…” 的伪装信息后就退出了。跟进数据段 off_4020，发现这里连续存放了 42 个指针（刚好 336 字节），每个指针指向一个 32 位的 MD5 字符串。 程序没有动态加密，而是将 Flag 拆成了单个字符，并将每个字符的 MD5 值按顺序硬编码在了数据段中。 通过简单的单字符 MD5 查表（或跑脚本爆破），将这 42 个 MD5 逐一映射回明文拼接所有破解出的单字符，得到： dart{2ab1fb8a-b830-45e7-8830-66c7e3b3e05a} re2查壳后发现是upx加壳的，并且有魔改,当时懒得脱了，插个眼后面复盘一下 re3附件一个pyinstaller打包的elf，一个.pcap，不出意料的话就是elf程序有加密逻辑，而流量中有加密结果，先流量分析发现客户像服务器端发送了三个文件加密结果，最终目标是解密flag.txt的加密结果（hex编码）解包后再将pyc扔进pylingual,拿到py源码123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960# Decompiled with PyLingual (https://pylingual.io)# Internal filename: &#x27;client.py&#x27;# Bytecode version: 3.10.b1 (3439)# Source timestamp: 1970-01-01 00:00:00 UTC (0)import base64import sysimport osimport jsonimport socketimport hashlibimport crypt_coreimport builtinsdef _oe(_d, _k1, _k2, _rn): # ***&lt;module&gt;._oe: Failure: Compilation Error try: _b = base64.b85decode(_d.encode()) _r = [] for _i, _x in enumerate(_b): return ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _i, 3) or ((_k1, _k2, _rn), _r.append(_x, _k if _k else None) _s = bytes(_r).decode() _res = [] for _c in _s: if _c.isalpha(): _base = ord(&#x27;A&#x27;) if _c.isupper() else ord(&#x27;a&#x27;) _res.append((chr, ord(_c), _base, _rn, 26, _base)) else: if _c.isdigit(): _res.append(str(int(_c),